  const activeAnimal = ANIMAIS_DOSSIER.find(a => a.id === activeAnimalId) || ANIMAIS_DOSSIER[0];

  const handleSimulateAudio = () => {
    setIsPlayingAudio(true);
    // Simulate web audio beep
    try {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const oscillator = audioCtx.createOscillator();
      const gainNode = audioCtx.createGain();
      
      oscillator.connect(gainNode);
      gainNode.connect(audioCtx.destination);
      
      oscillator.type = 'sine';
      oscillator.frequency.setValueAtTime(activeAnimalId === 'leao' ? 120 : 350, audioCtx.currentTime); // lower pitch for lion growl
      gainNode.gain.setValueAtTime(0.08, audioCtx.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.0001, audioCtx.currentTime + 1.2);
      
      oscillator.start();
      oscillator.stop(audioCtx.currentTime + 1.2);
    } catch (e) {
      // AudioContext blocker fallback
    }

    setTimeout(() => {
      setIsPlayingAudio(false);
    }, 1500);
  };

