                                const W = doc.internal.pageSize.getWidth();
                                const H = doc.internal.pageSize.getHeight();

                                // Background
                                doc.setFillColor(30, 15, 5);
                                doc.rect(0, 0, W, H, 'F');

                                // Header stripe
                                doc.setFillColor(200, 122, 36);
                                doc.rect(0, 0, W, 12, 'F');
