                                doc.text('MHMFarms · Notícias & Publicações', 10, 8);
                                doc.text(news.dataPub.substring(0,10), W - 10, 8, { align:'right' });

                                // Try to embed image
                                if (news.imagemUrl) {
                                  try {
                                    const res = await fetch(news.imagemUrl);
                                    const blob = await res.blob();
                                    const b64 = await new Promise<string>((resolve) => {
                                      const reader = new FileReader();
                                      reader.onloadend = () => resolve(reader.result as string);
                                      reader.readAsDataURL(blob);
                                    });
                                    const ext = blob.type.includes('png') ? 'PNG' : 'JPEG';
                                    doc.addImage(b64, ext, 10, 18, W - 20, 70);
                                  } catch {}
                                }

